#include <stdio.h>
#include <stdint.h>
#include <limits.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int64_t dp[N + 1][N + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= N; j++) {
                dp[i][j] = INT64_MAX;
            }
        }
        dp[0][0] = 0;
        int pi[N], ai[N];
        for (int i = 0; i < N - 1; i++) {
            scanf("%d %d", &pi[i], &ai[i]);
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= i; j++) {
                if (j > 0) {
                    dp[i][j] = dp[i - 1][j - 1];
                }
                if (i > 1) {
                    dp[i][j] = (dp[i][j] < dp[i - 1][j] + ai[i - 2]) ? dp[i][j] : dp[i - 1][j] + ai[i - 2];
                }
            }
        }
        printf("%lld\n", dp[N][K]);
    }
    return 0;
}

