public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            long[][] dp = new long[N + 1][N + 1];
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= N; j++) {
                    dp[i][j] = Long.MAX_VALUE;
                }
            }
            dp[0][0] = 0;
            int[] pi = new int[N];
            int[] ai = new int[N];
            for (int i = 0; i < N - 1; i++) {
                pi[i] = sc.nextInt();
                ai[i] = sc.nextInt();
            }
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j <= i; j++) {
                    if (j > 0) {
                        dp[i][j] = dp[i - 1][j - 1];
                    }
                    if (i > 1) {
                        dp[i][j] = Math.min(dp[i][j], dp[i - 1][j] + ai[i - 2]);
                    }
                }
            }
            System.out.println(dp[N][K]);
        }
    }
}

